const input = { ...$json };
const technicalReadme = String(
  input.technicalReadme ||
  input.output ||
  input.text ||
  input.response ||
  ''
).trim();

if (!technicalReadme) {
  throw new Error('Missing technicalReadme/output/text/response to save as Markdown file.');
}

const releaseVersion = String(
  input.releaseVersion ||
  input.release?.currentVersion ||
  input.raw?.release?.currentVersion ||
  input.raw?.raw?.release?.currentVersion ||
  'unknown'
).trim();

const baseDir = String(
  input.outputDir ||
  'C:/Users/mateo-soto/Desktop/proyectos/JsatReadme'
).trim().replace(/\\/g, '/').replace(/\/$/, '');

const readmeFileName = String(
  input.readmeFileName ||
  `README-release-${releaseVersion}.md`
).trim().replace(/[<>:"/\\|?*]+/g, '-');

const outputPath = `${baseDir}/${readmeFileName}`;

return {
  json: {
    ...input,
    kind: 'savedReadmeRequest',
    releaseVersion,
    readmeFileName,
    outputDir: baseDir,
    outputPath,
    technicalReadme,
  },
  binary: {
    data: {
      data: Buffer.from(technicalReadme, 'utf8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: readmeFileName,
      fileExtension: 'md',
    },
  },
};

return {
  json: {
    kind: 'savedReadmeResult',
    status: 'saved',
    outputPath: $json.outputPath,
    readmeFileName: $json.readmeFileName,
    releaseVersion: $json.releaseVersion,
    technicalReadme: $json.technicalReadme,
  },
};
